<?php
require 'login_check.php'; include 'db.php'; include 'config.php'; require_once 'lib/location_duplicates.php'; require_once 'lib/mapbox_search.php'; require_once 'lib/location_classifier.php'; require_once 'lib/location_hours.php';
if(!isset($_SESSION['user_id'])) craftcrawl_redirect('user_login.php');
$message=null; $user_id=(int)$_SESSION['user_id'];
$search_area=trim($_GET['area']??''); $search_name=trim($_GET['name_query']??''); $search_scope=($_GET['scope']??'area')==='broadened'?'broadened':'area';
$allowed_location_types=['brewery','winery','cidery','distillery','meadery','bar','social_club']; $search_results=[]; $selected_candidate=null; $manual_mode=($_GET['manual']??'')==='1';
if($search_area!==''){$search_results=craftcrawl_mapbox_import_candidates($MAPBOX_ACCESS_TOKEN,'any',$search_area,10,$search_scope,$search_name);}
if(!empty($_GET['selected'])){$selected_candidate=json_decode(base64_decode($_GET['selected']),true);if(is_array($selected_candidate)){$manual_mode=true;}else{$selected_candidate=null;}}
function clean_text($v){return trim(strip_tags($v??''));}
function suggestion_hours_from_post($value){$decoded=json_decode((string)$value,true);return is_array($decoded)&&craftcrawl_validate_business_hours($decoded)===null?$decoded:null;}
if($_SERVER['REQUEST_METHOD']==='POST'){
 craftcrawl_verify_csrf();
 $name=clean_text($_POST['suggested_name']??''); $type=clean_text($_POST['suggested_type']??''); $place=clean_text($_POST['mapbox_place_id']??'');
 $address=clean_text($_POST['address_address-search']??$_POST['address']??''); $apt=clean_text($_POST['apt_suite']??''); $city=clean_text($_POST['city']??''); $state=strtoupper(clean_text($_POST['state']??'')); $zip=clean_text($_POST['zip']??'');
 $lat=filter_var($_POST['latitude']??null,FILTER_VALIDATE_FLOAT); $lng=filter_var($_POST['longitude']??null,FILTER_VALIDATE_FLOAT); $phone=clean_text($_POST['phone']??''); $website=filter_var(trim($_POST['website']??''),FILTER_SANITIZE_URL); $notes=clean_text($_POST['user_notes']??''); $provider_hours=suggestion_hours_from_post($_POST['provider_hours_json']??''); $provider_hours_json=$provider_hours?json_encode($provider_hours):null;
 if($name===''||!in_array($type,$allowed_location_types,true)||$place===''||$address===''||$city===''||$state===''||$lat===false||$lng===false){
  $missing=[];
  if($name==='')$missing[]='name'; if(!in_array($type,$allowed_location_types,true))$missing[]='type'; if($place==='')$missing[]='place selection ID'; if($address==='')$missing[]='street address'; if($city==='')$missing[]='city'; if($state==='')$missing[]='state'; if($lat===false||$lng===false)$missing[]='coordinates';
  $message='Please choose an exact address result and complete the required fields. Missing: '.implode(', ',$missing).'.';
 }
 else { $s=$conn->prepare("INSERT INTO location_suggestions (suggested_by_user_id,suggested_name,suggested_type,mapbox_place_id,street_address,apt_suite,city,state,zip,latitude,longitude,phone,website,user_notes,provider_hours_json,createdAt) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,NOW())"); $s->bind_param('issssssssddssss',$user_id,$name,$type,$place,$address,$apt,$city,$state,$zip,$lat,$lng,$phone,$website,$notes,$provider_hours_json); $s->execute(); craftcrawl_redirect('user/portal.php?message=suggestion_saved'); }
}
?>
