<section class="admin-panel business-add-location-search-panel"><h2>Find the location</h2><form method="GET" class="admin-search-form business-location-claim-search"><div class="admin-field"><label for="area">City, ZIP, or area</label><input id="area" name="area" required value="<?php echo escape_output($search_area);?>"></div><div class="admin-field"><label for="name_query">Business name</label><input id="name_query" name="name_query" value="<?php echo escape_output($search_name);?>" placeholder="Optional"></div><button type="submit">Search</button></form><?php if($search_area!==''):?><div class="business-section-header"><h3><?php echo $search_scope==='broadened'?'Broadened Results':'Results';?></h3><?php if($search_scope==='area'):?><a href="?area=<?php echo rawurlencode($search_area);?>&name_query=<?php echo rawurlencode($search_name);?>&scope=broadened">Broaden search</a><?php else:?><a href="?area=<?php echo rawurlencode($search_area);?>&name_query=<?php echo rawurlencode($search_name);?>">Return to exact area search</a><?php endif;?></div><?php if(empty($search_results)):?><p>No Mapbox results found.</p><?php endif;?><?php foreach($search_results as $result):$candidate=base64_encode(json_encode(['name'=>$result['name'],'suggested_type'=>'','street_address'=>$result['street_address'],'city'=>$result['city'],'state'=>$result['state'],'zip'=>$result['zip'],'latitude'=>$result['latitude'],'longitude'=>$result['longitude'],'mapbox_place_id'=>$result['source_place_id'],'phone'=>$result['phone']??'','website'=>$result['website']??'','opening_hours'=>$result['opening_hours']??null]));?><article class="admin-list-item"><div><h3><?php echo escape_output($result['name']);?></h3><p><?php echo escape_output($result['full_address']);?></p></div><a href="?selected=<?php echo rawurlencode($candidate);?>">Use this location</a></article><?php endforeach;?><?php endif;?><button type="button" class="business-manual-location-toggle" data-manual-location-toggle aria-expanded="<?php echo $manual_mode?'true':'false';?>">Can’t find it? Enter location manually</button></section>
<form class="business-add-location-form<?php echo $manual_mode?' is-visible':'';?>" data-manual-location-form <?php echo $manual_mode?'':'hidden';?> method="POST"><?php echo craftcrawl_csrf_input();?><label for="suggested_name">Name</label><input id="suggested_name" name="suggested_name" required value="<?php echo escape_output($selected_candidate['name']??'');?>"><label for="suggested_type">Type</label><select id="suggested_type" name="suggested_type" required><option value="">--Please Select a Type--</option><option value="brewery" <?php echo ($selected_candidate['suggested_type']??'')==='brewery'?'selected':'';?>>Brewery</option><option value="winery" <?php echo ($selected_candidate['suggested_type']??'')==='winery'?'selected':'';?>>Winery</option><option value="cidery" <?php echo ($selected_candidate['suggested_type']??'')==='cidery'?'selected':'';?>>Cidery</option><option value="distillery" <?php echo ($selected_candidate['suggested_type']??'')==='distillery'?'selected':'';?>>Distillery</option><option value="meadery" <?php echo ($selected_candidate['suggested_type']??'')==='meadery'?'selected':'';?>>Meadery</option><option value="bar" <?php echo ($selected_candidate['suggested_type']??'')==='bar'?'selected':'';?>>Bar</option><option value="social_club" <?php echo ($selected_candidate['suggested_type']??'')==='social_club'?'selected':'';?>>Social Club</option></select><label for="street_address">Street Address</label><input id="street_address" name="address" required autocomplete="address-line1" value="<?php echo escape_output($selected_candidate['street_address']??'');?>"><p class="form-help">Start typing a street address and select an exact result.</p><label for="apt_suite">Apartment / Suite</label><input id="apt_suite" name="apt_suite"><div class="business-form-row business-form-row-address"><div><label for="city">City</label><input id="city" name="city" readonly required value="<?php echo escape_output($selected_candidate['city']??'');?>"></div><div><label for="state">State</label><input id="state" name="state" readonly required value="<?php echo escape_output($selected_candidate['state']??'');?>"></div><div><label for="zip">ZIP</label><input id="zip" name="zip" readonly value="<?php echo escape_output($selected_candidate['zip']??'');?>"></div></div><input id="latitude" name="latitude" type="hidden" value="<?php echo escape_output($selected_candidate['latitude']??'');?>"><input id="longitude" name="longitude" type="hidden" value="<?php echo escape_output($selected_candidate['longitude']??'');?>"><input id="mapbox_place_id" name="mapbox_place_id" type="hidden" value="<?php echo escape_output($selected_candidate['mapbox_place_id']??'');?>"><input id="provider_hours_json" name="provider_hours_json" type="hidden" value="<?php echo escape_output(!empty($selected_candidate['opening_hours'])?json_encode($selected_candidate['opening_hours']):'');?>"><label for="phone">Phone</label><input id="phone" name="phone" value="<?php echo escape_output($selected_candidate['phone']??'');?>"><label for="website">Website</label><input id="website" name="website" type="url" value="<?php echo escape_output($selected_candidate['website']??'');?>"><label for="user_notes">Notes</label><textarea id="user_notes" name="user_notes"></textarea><button type="submit">Submit Suggestion</button></form></main><script>window.MAPBOX_ACCESS_TOKEN = <?php echo json_encode($MAPBOX_ACCESS_TOKEN); ?>;</script><script src="<?php echo escape_output(craftcrawl_app_base_path() . '/js/business_account_creation.js'); ?>?v=<?php echo filemtime(__DIR__.'/js/business_account_creation.js');?>"></script><script src="<?php echo escape_output(craftcrawl_app_base_path() . '/js/location_suggestion.js'); ?>?v=<?php echo filemtime(__DIR__.'/js/location_suggestion.js');?>"></script></body></html>
